// ==========================================
// RESOURCE ALLOCATOR — Dynamic Priority
// Translates strategy → concrete agent commands
// ==========================================
const strategy = $('Read Latest Strategy').first()?.json || {};
const content = $('Read Content Status').all();
const revenue = $('Read Revenue Status').all();

const now = new Date();
const deadline = new Date('2026-04-05T23:59:59');
const hoursLeft = Math.max(0, Math.round((deadline - now) / (1000 * 60 * 60)));
const daysLeft = Math.round(hoursLeft / 24);

// Current state
const totalCustomers = revenue.length;
const target = 1500;
const remaining = target - totalCustomers;

const totalVideos = content.length;
const publishedLast6h = content.filter(c => {
  const pub = new Date(c.json.published_at || c.json['Published At'] || c.json.createdTime || 0);
  return (now - pub) < 6 * 60 * 60 * 1000;
}).length;
const totalDMs = content.reduce((s, c) => s + (c.json.dms_generated || c.json['DMs Generated'] || 0), 0);
const pendingLeads = revenue.filter(r => (r.json.status || r.json.Status) === 'pending').length;

// Strategy percentages (from Strategic Brain)
const contentPct = strategy.content_pct || 40;
const salesPct = strategy.sales_pct || 30;
const intelPct = 10;
const experimentPct = 20;

// === DYNAMIC ALLOCATION RULES ===
const commands = [];

// 1. Content Production
if (publishedLast6h < 3) {
  commands.push({
    agent: 'content_engine',
    action: `أنتج ${Math.max(5, 10 - publishedLast6h)} فيديوهات فوراً`,
    priority: 'critical',
    reason: `آخر 6 ساعات: ${publishedLast6h} فيديو فقط — أقل من المطلوب`,
    allocation_pct: Math.min(60, contentPct + 20)
  });
} else if (publishedLast6h >= 5) {
  commands.push({
    agent: 'content_engine',
    action: 'استمر بنفس الوتيرة — الإنتاج جيد',
    priority: 'medium',
    reason: `${publishedLast6h} فيديو في 6 ساعات — ممتاز`,
    allocation_pct: contentPct
  });
}

// 2. Sales Closing
if (pendingLeads >= 3) {
  commands.push({
    agent: 'warda',
    action: `عندك ${pendingLeads} leads معلقين — اقفليهم الحين`,
    priority: 'critical',
    reason: 'leads جاهزين للدفع — أسرع طريق للإيراد',
    allocation_pct: Math.min(50, salesPct + 15)
  });
} else if (totalDMs > 20 && totalCustomers < 10) {
  commands.push({
    agent: 'warda',
    action: 'ركزي على Close — فيه DMs كثير لكن المبيعات ضعيفة',
    priority: 'high',
    reason: `${totalDMs} DM لكن ${totalCustomers} عميل فقط`,
    allocation_pct: salesPct + 10
  });
}

// 3. Competitor Intel
if (daysLeft <= 3) {
  commands.push({
    agent: 'wolf',
    action: 'أوقف التحليل — ركز كل شيء على الإغلاق',
    priority: 'low',
    reason: 'آخر 3 أيام — مافيه وقت للتحليل',
    allocation_pct: 0
  });
} else {
  commands.push({
    agent: 'wolf',
    action: 'راقب المنافسين + جدد الـ Hooks',
    priority: 'medium',
    reason: 'مطلوب بيانات جديدة كل 6 ساعات',
    allocation_pct: intelPct
  });
}

// 4. Experimentation
if (daysLeft > 5) {
  commands.push({
    agent: 'ab_testing',
    action: 'جرب 2 Hooks جديدة — ابحث عن Gold',
    priority: 'medium',
    reason: 'فيه وقت للتجربة',
    allocation_pct: experimentPct
  });
} else {
  commands.push({
    agent: 'ab_testing',
    action: 'أوقف التجارب — استخدم اللي ثبت نجاحه فقط',
    priority: 'high',
    reason: 'لا وقت للتجربة — نفذ بالمثبت',
    allocation_pct: 5
  });
}

// 5. Emergency mode
if (daysLeft <= 2 && remaining > 10) {
  commands.push({
    agent: 'borhan',
    action: '🚨 EMERGENCY MODE — كل الموارد على الإغلاق + Flash Sale',
    priority: 'critical',
    reason: `باقي ${daysLeft} يوم و ${remaining} عميل — طوارئ`,
    allocation_pct: 100
  });
}

// 6. Almost there
if (remaining <= 5 && remaining > 0) {
  commands.push({
    agent: 'borhan',
    action: `💪 باقي ${remaining} عملاء فقط — Push أخير لكل Lead مفتوح`,
    priority: 'high',
    reason: 'قريبين جداً — لا تتوقف',
    allocation_pct: 80
  });
}

return {
  json: {
    timestamp: now.toISOString(),
    state: {
      customers: totalCustomers,
      remaining,
      days_left: daysLeft,
      hours_left: hoursLeft,
      videos_last_6h: publishedLast6h,
      total_dms: totalDMs,
      pending_leads: pendingLeads
    },
    commands,
    mode: daysLeft <= 2 ? 'EMERGENCY' : daysLeft <= 5 ? 'SPRINT' : 'NORMAL'
  }
};

